# Step 1: write to outbox inside the business transaction
def create_order(order_data: dict):
    with db.transaction():
        order = Order.create(**order_data)
        # Write message to outbox in the same transaction
        Outbox.create(
            idempotency_key=f"order_created:{order.id}",
            topic="orders",
            payload=json.dumps({
                "idempotency_key": f"order_created:{order.id}",
                "event": "order_created",
                "order_id": str(order.id),
            }),
            published=False
        )
        db.commit()
    # Transaction committed; outbox relay picks up from here

# Step 2: relay process (runs as a separate cron or loop)
def relay_outbox():
    pending = Outbox.filter(published=False).order_by('created_at')[:100]
    for record in pending:
        try:
            broker.publish(record.topic, json.loads(record.payload))
            record.update(published=True)
        except Exception:
            log.exception("relay failed for %s", record.idempotency_key)
